import { API_URL } from '../config.js';

const FILES_ROOT = `${API_URL}/api/files`;

export const IMAGE_SCOPES = ['food', 'meal', 'ai'] as const;
export type ImageScope = typeof IMAGE_SCOPES[number];

export interface UploadImageResponse {
    /** Directory key (e.g. 'images/food/<uuidv7>'); append /display.jpg or /original.<ext>. */
    image_path: string;
}

export type UploadOrQueueResult =
    | { status: 'uploaded'; image_path: string }
    | { status: 'queued'; queue_id: string };

/**
 * Thrown by `uploadImage` on a non-OK HTTP response. The `status` field lets
 * callers branch on response category (4xx vs 5xx) without text-matching the
 * message — only 5xx and 0 (offline) should fall through to the queue.
 */
export class ImageUploadError extends Error {
    constructor(public readonly status: number, message: string) {
        super(message);
        this.name = 'ImageUploadError';
    }
}

export class FilesService {
    /**
     * Upload a single image via multipart/form-data. Story 124 — the server
     * keeps the original bytes and produces a progressive display.jpg.
     *
     * Throws `ImageUploadError` for HTTP failures (with `status`), or a
     * native `TypeError` when fetch itself rejects (offline / DNS / aborted).
     */
    static async uploadImage(scope: ImageScope, blob: Blob, filename = 'photo'): Promise<UploadImageResponse> {
        const form = new FormData();
        form.set('image', blob, filename);
        // Story 210: the service worker aborts /api/* requests after 15s
        // unless X-Manual-AbortSignal opts out. Originals are 5-12 MB (story
        // 124 — no client resize) and routinely need >15s on cellular over
        // the VPN; the 2026-06-10 incident saw 56-68s uploads that SUCCEEDED
        // server-side while the client had already given up. Manage our own
        // generous budget instead — a genuinely dead connection still rejects
        // and falls into the upload queue.
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 180_000);
        let response: Response;
        try {
            response = await fetch(`${FILES_ROOT}/images?scope=${encodeURIComponent(scope)}`, {
                method: 'POST',
                headers: { 'X-Manual-AbortSignal': 'true' },
                body: form,
                signal: controller.signal,
            });
        } finally {
            clearTimeout(timeoutId);
        }
        if (!response.ok) {
            // Read the body exactly once; opportunistically parse JSON.
            // Calling .json() then .text() (or vice versa) on a real Response
            // throws "body stream already read".
            const raw = await response.text().catch(() => '');
            let parsed: { error?: string } | null = null;
            if (raw) {
                try { parsed = JSON.parse(raw) as { error?: string }; } catch { /* not JSON */ }
            }
            const message = parsed?.error
                ?? (raw
                    ? `Image upload failed (${response.status}): ${raw.slice(0, 200)}`
                    : `Image upload failed: ${response.status}`);
            throw new ImageUploadError(response.status, message);
        }
        const data = await response.json().catch(() => null) as UploadImageResponse | null;
        if (!data?.image_path) {
            throw new Error('Image upload returned no image_path');
        }
        return data;
    }

    /**
     * Upload directly when online and healthy; otherwise enqueue the bytes
     * (story 124) and register a Background Sync to ship later.
     *
     * Falls through to the queue for: native fetch failures (TypeError —
     * offline, DNS, CORS, aborted), 5xx responses, or `navigator.onLine`
     * being false. 4xx responses re-throw — queueing won't change the
     * outcome of a 413 / 415 / etc.
     */
    static async uploadImageOrQueue(
        scope: ImageScope,
        blob: Blob,
        filename = 'photo',
        options: { local_ref?: string } = {},
    ): Promise<UploadOrQueueResult> {
        try {
            const { image_path } = await this.uploadImage(scope, blob, filename);
            return { status: 'uploaded', image_path };
        } catch (err) {
            if (!shouldQueue(err)) throw err;

            const storeMod = await import('./offline/image-upload-store.js');
            const shippingMod = await import('./offline/image-upload-shipping.js');
            const queue_id = await storeMod.enqueueImageUpload(scope, blob, filename, { local_ref: options.local_ref });
            try {
                await shippingMod.requestImageUploadSync();
            } catch (syncErr) {
                // Background Sync unavailable — the queue still drains on
                // `online` (see app.ts). Don't fail the caller.
                console.warn('Background sync registration failed:', syncErr);
            }
            return { status: 'queued', queue_id };
        }
    }

    /** Absolute URL for a specific variant of a stored image. */
    static variantUrl(imagePath: string, variant: 'display.jpg' | 'original.jpg' | 'original.jpeg' | 'original.png' | 'original.webp'): string {
        return `${API_URL}/api/files/${imagePath}/${variant}`;
    }
}

function shouldQueue(err: unknown): boolean {
    if (typeof navigator !== 'undefined' && !navigator.onLine) return true;
    if (err instanceof TypeError) return true; // fetch network failure
    if (err instanceof ImageUploadError && err.status >= 500 && err.status <= 599) return true;
    return false;
}
